 402→#[cfg(test)]
 403→mod tests {
 404→    use super::*;
 405→    use crate::batch_analyze::{FunctionEntry, FunctionRegistry};
 406→    use crate::protocol::{DependencyKind, ExternalDependency};
 407→    use crate::types::TypeInfo;
 408→    use std::collections::HashMap;
 409→    use std::path::PathBuf;
 410→
 411→    /// Helper: build a FunctionRegistry from a list of (file, name, deps) tuples.
 412→    /// Each dep is a symbol name (no source_module disambiguation).
 413→    fn make_registry(
 414→        funcs: &[(&str, &str, Vec<&str>)],
 415→    ) -> FunctionRegistry {
 416→        let mut entries = Vec::new();
 417→        let mut index = HashMap::new();
 418→
 419→        for (file, name, deps) in funcs {
 420→            let qn = FunctionRegistry::qualified_name(
 421→                &PathBuf::from(file),
 422→                name,
 423→            );
 424→            let idx = entries.len();
 425→            index.insert(qn, idx);
 426→            entries.push(FunctionEntry {
 427→                file_path: PathBuf::from(file),
 428→                name: name.to_string(),
 429→                exported: true,
 430→                params: vec![],
 431→                return_type: TypeInfo::Unknown,
 432→                dependencies: deps
 433→                    .iter()
 434→                    .map(|s| ExternalDependency {
 435→                        kind: DependencyKind::FunctionCall,
 436→                        symbol: s.to_string(),
 437→                        source_module: String::new(),
 438→                        return_type: TypeInfo::Unknown,
 439→                        param_types: vec![],
 440→                        call_sites: vec![],
 441→                    })
 442→                    .collect(),
 443→                branch_count: 0,
 444→                start_line: 1,
 445→                end_line: 10,
 446→                crypto_boundaries: vec![],
 447→            });
 448→        }
 449→
 450→        FunctionRegistry::from_raw(entries, index)
 451→    }
 452→
 453→    /// Helper: build registry with source_module on dependencies.
 454→    fn make_registry_with_modules(
 455→        funcs: &[(&str, &str, Vec<(&str, &str)>)],
 456→    ) -> FunctionRegistry {
 457→        let mut entries = Vec::new();
 458→        let mut index = HashMap::new();
 459→
 460→        for (file, name, deps) in funcs {
 461→            let qn = FunctionRegistry::qualified_name(
 462→                &PathBuf::from(file),
 463→                name,
 464→            );
 465→            let idx = entries.len();
 466→            index.insert(qn, idx);
 467→            entries.push(FunctionEntry {
 468→                file_path: PathBuf::from(file),
 469→                name: name.to_string(),
 470→                exported: true,
 471→                params: vec![],
 472→                return_type: TypeInfo::Unknown,
 473→                dependencies: deps
 474→                    .iter()
 475→                    .map(|(sym, module)| ExternalDependency {
 476→                        kind: DependencyKind::FunctionCall,
 477→                        symbol: sym.to_string(),
 478→                        source_module: module.to_string(),
 479→                        return_type: TypeInfo::Unknown,
 480→                        param_types: vec![],
 481→                        call_sites: vec![],
 482→                    })
 483→                    .collect(),
 484→                branch_count: 0,
 485→                start_line: 1,
 486→                end_line: 10,
 487→                crypto_boundaries: vec![],
 488→            });
 489→        }
 490→
 491→        FunctionRegistry::from_raw(entries, index)
 492→    }
